 1	import React, { FC } from 'react';
 2	import { useLocation, useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import { NetworkPolicyModel } from '@kubevirt-ui/kubevirt-api/console';
 5	import {
 6	  Button,
 7	  EmptyState,
 8	  EmptyStateActions,
 9	  EmptyStateFooter,
10	} from '@patternfly/react-core';
11	import { DEFAULT_NAMESPACE } from '@utils/constants';
12	import { SHARED_DEFAULT_PATH_NEW_RESOURCE_FORM } from '@utils/constants/ui';
13	import { useLastNamespacePath } from '@utils/hooks/useLastNamespacePath';
14	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
15	import { MultiNetworkPolicyModel } from '@utils/models';
16	import { resourcePathFromModel } from '@utils/resources/shared';
17	import { isEmpty } from '@utils/utils';
18	
19	const NetworkPolicyEmptyState: FC = () => {
20	  const { t } = useNetworkingTranslation();
21	  const lastNamespacePath = useLastNamespacePath();
22	  const location = useLocation();
23	
24	  const networkModel = isEmpty(location.pathname.match(MultiNetworkPolicyModel.kind))
25	    ? NetworkPolicyModel
26	    : MultiNetworkPolicyModel;
27	
28	  const navigate = useNavigate();
29	
30	  return (
31	    <EmptyState
32	      headingLevel="h4"
33	      titleText={t('No {{kind}} found', { kind: networkModel.kind })}
34	    >
35	      <EmptyStateFooter>
36	        <EmptyStateActions>
37	          <Button
38	            onClick={() =>
39	              navigate(
40	                `${resourcePathFromModel(
41	                  NetworkPolicyModel,
42	                  null,
43	                  lastNamespacePath || DEFAULT_NAMESPACE,
44	                )}/${SHARED_DEFAULT_PATH_NEW_RESOURCE_FORM}`,
45	              )
46	            }
47	          >
48	            {t('Create {{kind}}', { kind: networkModel.kind })}
49	          </Button>
50	        </EmptyStateActions>
51	      </EmptyStateFooter>
52	    </EmptyState>
53	  );
54	};
55	
56	export default NetworkPolicyEmptyState;

